                if (hasWs) g.has_ws = true;
                // A workstation with a manually overridden target uses its own takt, not the line's.
                if (!g.takt_time_seconds) {
                    const rowTakt = p.is_custom_takt ? (parseFloat(p.takt_time_seconds || 0) || 0) : 0;
