                const otTakt   = (otSecs > 0 && otTarget > 0) ? otSecs / otTarget : 0;
                g.ot_eff    = (hasLineOT && wsOtMins > 0 && otTakt > 0 && g.has_ws) ? (g.sam / otTakt) * 100 : null;
                g.total_eff = (g.reg_eff != null && g.ot_eff != null)
